import React from 'react';
import { Item } from '../../types';

interface TicketProps {
    orderItems: (Item | null)[];
    addToOrder: (item: Item) => void;
}

const Ticket: React.FC<TicketProps> = ({ orderItems, addToOrder }) => {
    return (
        <div className="flex flex-col gap-3 p-3">
            {orderItems.map((item, index) => (
                item ? (
                    <div key={item.id} className="flex items-center gap-3 p-2 bg-gray-100 dark:bg-gray-800 rounded-lg shadow-sm border border-slate-200 dark:border-slate-700">
                      {/* item is an Item, can safely access all properties */}
                      {item.representation === 'image' && item.imageUrl ? (
                        <img
                          src={item.imageUrl}
                          alt={item.name}
                          className="w-16 h-16 object-cover rounded-md"
                        />
                      ) : (
                          <div
                              style={{ backgroundColor: item.color }}
                              className={`w-16 h-16 rounded-md flex items-center justify-center
                                ${item.shape === 'circle' ? 'rounded-full' : 'rounded-lg'}`}
                          >
                              {/* Content could be any text or image here */}
                          </div>
                      )}
                      <div>
                          <p className="text-sm font-semibold">{item.name}</p>
                          <p className="text-xs text-gray-500">{item.category}</p>
                      </div>
                      <button onClick={() => addToOrder(item)} className="ml-auto text-blue-500 hover:text-blue-700 focus:outline-none">
                          Add More
                      </button>
                    </div>
                ) : null
            ))}
        </div>
    );
};

export default Ticket;
```


